import { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const LoginPage = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const { login } = useAuth(); // Galing sa AuthContext
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    
    try {
      // Tinatawag ang login function mula sa AuthContext
      const loggedInUser = await login(email, password);
      
      // I-check kung may bumalik na user at kung ano ang role nito
      if (loggedInUser && loggedInUser.role === 'admin') {
        navigate('/admin');
      } else if (loggedInUser) {
        navigate('/home');
      } else {
        setError('Login failed. No user data received.');
      }
      
    } catch (err) {
      setError('Login failed. Please try again.');
    }
  };

  return (
    <div className='login-page' style={{ padding: '50px', textAlign: 'center' }}>
      <h2>Login to Mi Ilao</h2>
      {error && <p style={{ color: 'red' }}>{error}</p>}
      <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '10px', maxWidth: '300px', margin: '0 auto' }}>
        <input 
          type='email' 
          placeholder='Email address'
          value={email} 
          onChange={e => setEmail(e.target.value)} 
          required 
          style={{ padding: '10px' }}
        />
        <input 
          type='password' 
          placeholder='Password'
          value={password} 
          onChange={e => setPassword(e.target.value)} 
          required
          style={{ padding: '10px' }}
        />
        <button type='submit' style={{ padding: '10px', backgroundColor: '#ff69b4', color: 'white', border: 'none', cursor: 'pointer' }}>
          Login
        </button>
      </form>
      <p>Don't have an account? <Link to='/register'>Register here</Link></p>
    </div>
  );
};

export default LoginPage;
